    /**
     * Get today's quote using deterministic day-of-year selection.
     * Same quote for all users on a given day.
     */
    fun todayQuote(): Quote {
        val calendar = Calendar.getInstance()
        val dayOfYear = calendar.get(Calendar.DAY_OF_YEAR)
        val index = (dayOfYear - 1) % allQuotes.size
        return allQuotes[index]
    }

    /**
     * Get a quote for a specific day offset from today.
     */
    fun quoteForDayOffset(offset: Int): Quote {
        val calendar = Calendar.getInstance()
        calendar.add(Calendar.DAY_OF_YEAR, offset)
        val dayOfYear = calendar.get(Calendar.DAY_OF_YEAR)
        val index = (dayOfYear - 1) % allQuotes.size
        return allQuotes[index]
    }

    /**
     * Get quotes for a specific category.
     */
    fun quotesForCategory(category: QuoteCategory): List<Quote> {
        return allQuotes.filter { it.category == category }
    }

    /**
     * Get recent archive quotes (past N days).
     */
    fun archiveQuotes(days: Int = 30): List<Quote> {
        return (1..days).map { offset ->
            quoteForDayOffset(-offset)
        }
    }
}
